from flask import Flask, request, redirect, url_for
import requests

app = Flask(__name__)

# Configuration for OAuth2 Client
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
AUTH_URL = 'https://auth.example.com/oauth/authorize'
TOKEN_URL = 'https://auth.example.com/oauth/token'

@app.route('/login')
def login():
    redirect_uri = request.args.get('redirect_uri')
    domain = 'example.com'  # Replace with your base domain

    if not redirect_uri or not domain in redirect_uri:
        return "Invalid redirect URI", 400

    auth_params = {
        'response_type': 'code',
        'client_id': CLIENT_ID,
        'redirect_uri': redirect_uri,
        'scope': 'openid profile email'
    }

    auth_url = f"{AUTH_URL}?{requests.compat.urlencode(auth_params)}"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    redirect_uri = request.args.get('redirect_uri')

    token_params = {
        'grant_type': 'authorization_code',
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET,
        'code': code,
        'redirect_uri': redirect_uri
    }

    response = requests.post(TOKEN_URL, data=token_params)
    access_token = response.json().get('access_token')

    # Redirect to the provided redirect URI with access token
    return redirect(f"{redirect_uri}?access_token={access_token}")

if __name__ == '__main__':
    app.run(debug=True)